import React, { useRef, useEffect } from 'react';

const WINDOW = 100;
const LERP_SPEED = 0.18; // how fast displayed values chase target (0-1, higher = snappier)
const YMAX_LERP = 0.05; // how fast yMax adapts (slow = stable axis)

function SignalChart({ dataRef, tOn, tOff }) {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const dimsRef = useRef({ w: 600, h: 180 });
  const displayedRef = useRef(new Float64Array(WINDOW)); // smoothed values
  const lenRef = useRef(0); // how many points are currently active
  const prevRawLenRef = useRef(0); // track previous raw length to detect new points
  const smoothYMaxRef = useRef(2.0); // smoothed Y-axis maximum
  const rafRef = useRef(null);

  // Track container size (no state needed)
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;
    const updateSize = () => {
      const rect = container.getBoundingClientRect();
      if (rect.width > 0) {
        dimsRef.current = { w: rect.width, h: 180 };
      }
    };
    updateSize();
    window.addEventListener('resize', updateSize);
    return () => window.removeEventListener('resize', updateSize);
  }, []);

  // 60fps animation loop
  useEffect(() => {
    const draw = () => {
      const canvas = canvasRef.current;
      if (!canvas) { rafRef.current = requestAnimationFrame(draw); return; }

      const { w: W, h: H } = dimsRef.current;
      const dpr = window.devicePixelRatio || 1;

      // Resize canvas only when needed
      const targetW = Math.round(W * dpr);
      const targetH = Math.round(H * dpr);
      if (canvas.width !== targetW || canvas.height !== targetH) {
        canvas.width = targetW;
        canvas.height = targetH;
        canvas.style.width = W + 'px';
        canvas.style.height = H + 'px';
      }

      const ctx = canvas.getContext('2d');
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

      const PAD_L = 45;
      const PAD_R = 60;
      const PAD_T = 10;
      const PAD_B = 10;
      const plotW = W - PAD_L - PAD_R;
      const plotH = H - PAD_T - PAD_B;

      // --- Interpolate displayed values toward target ---
      const raw = dataRef.current || [];
      const targetLen = Math.min(raw.length, WINDOW);
      const displayed = displayedRef.current;
      const prevRawLen = prevRawLenRef.current;
      const newPoints = raw.length - prevRawLen; // how many new samples arrived
      prevRawLenRef.current = raw.length;

      // Shift the displayed buffer left by the number of new points so each
      // slot continues tracking the same logical data point (no target-swap jitter).
      if (newPoints > 0 && lenRef.current > 0) {
        const shift = Math.min(newPoints, lenRef.current);
        if (shift < lenRef.current) {
          displayed.copyWithin(0, shift, lenRef.current);
        }
        // Initialize the newly-exposed trailing slots to the raw target directly
        const kept = lenRef.current - shift;
        for (let i = kept; i < targetLen; i++) {
          const rawVal = raw[raw.length - targetLen + i];
          displayed[i] = typeof rawVal === 'number' ? rawVal : (rawVal?.y ?? 0);
        }
        lenRef.current = targetLen;
      } else if (targetLen > lenRef.current) {
        // First fill — no shift needed, just init new slots
        for (let i = lenRef.current; i < targetLen; i++) {
          const rawVal = raw[raw.length - targetLen + i];
          displayed[i] = typeof rawVal === 'number' ? rawVal : (rawVal?.y ?? 0);
        }
        lenRef.current = targetLen;
      } else if (targetLen < lenRef.current) {
        lenRef.current = targetLen;
      }

      // Lerp existing points toward their (correctly aligned) targets
      for (let i = 0; i < lenRef.current; i++) {
        const rawVal = raw[raw.length - lenRef.current + i];
        const target = typeof rawVal === 'number' ? rawVal : (rawVal?.y ?? 0);
        displayed[i] += (target - displayed[i]) * LERP_SPEED;
      }

      const curLen = lenRef.current;

      // --- Compute Y range (smoothed to prevent axis jitter) ---
      let instantYMax = 2.0;
      for (let i = 0; i < curLen; i++) {
        if (displayed[i] > instantYMax) instantYMax = displayed[i];
      }
      instantYMax = Math.max(instantYMax * 1.2, tOn * 1.5, 2.0);
      // Smoothly adapt yMax — grow fast, shrink slowly
      const prev = smoothYMaxRef.current;
      if (instantYMax > prev) {
        smoothYMaxRef.current = prev + (instantYMax - prev) * 0.3; // fast grow
      } else {
        smoothYMaxRef.current = prev + (instantYMax - prev) * YMAX_LERP; // slow shrink
      }
      const yMax = smoothYMaxRef.current;

      const toX = (i) => PAD_L + (i / (WINDOW - 1)) * plotW;
      const toY = (v) => PAD_T + plotH - (Math.min(v, yMax) / yMax) * plotH;

      // --- Clear ---
      ctx.clearRect(0, 0, W, H);

      // Background
      ctx.fillStyle = '#fafafa';
      ctx.fillRect(PAD_L, PAD_T, plotW, plotH);

      // Grid lines
      ctx.strokeStyle = '#e8e8ec';
      ctx.lineWidth = 1;
      ctx.setLineDash([]);
      const yTicks = [0, yMax * 0.25, yMax * 0.5, yMax * 0.75, yMax];
      for (const v of yTicks) {
        const y = toY(v);
        ctx.beginPath();
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(PAD_L + plotW, y);
        ctx.stroke();
      }

      // Y axis labels
      ctx.fillStyle = '#999';
      ctx.font = '11px Inter, sans-serif';
      ctx.textAlign = 'right';
      ctx.textBaseline = 'middle';
      for (const v of yTicks) {
        ctx.fillText(v.toFixed(1), PAD_L - 6, toY(v));
      }

      // T_ON reference line
      if (tOn <= yMax) {
        const y = toY(tOn);
        ctx.strokeStyle = '#e05555';
        ctx.lineWidth = 1.2;
        ctx.setLineDash([6, 3]);
        ctx.beginPath();
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(PAD_L + plotW, y);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.fillStyle = '#e05555';
        ctx.font = '10px Inter, sans-serif';
        ctx.textAlign = 'left';
        ctx.fillText(`T_ON=${tOn}`, PAD_L + plotW + 4, y);
      }

      // T_OFF reference line
      if (tOff <= yMax) {
        const y = toY(tOff);
        ctx.strokeStyle = '#e0a030';
        ctx.lineWidth = 1;
        ctx.setLineDash([6, 3]);
        ctx.beginPath();
        ctx.moveTo(PAD_L, y);
        ctx.lineTo(PAD_L + plotW, y);
        ctx.stroke();
        ctx.setLineDash([]);
        ctx.fillStyle = '#e0a030';
        ctx.font = '10px Inter, sans-serif';
        ctx.textAlign = 'left';
        ctx.fillText(`T_OFF=${tOff}`, PAD_L + plotW + 4, y);
      }

      // Signal line
      if (curLen > 1) {
        ctx.strokeStyle = '#5b6abf';
        ctx.lineWidth = 2;
        ctx.lineJoin = 'round';
        ctx.lineCap = 'round';
        ctx.setLineDash([]);
        ctx.beginPath();
        const offset = WINDOW - curLen;
        for (let i = 0; i < curLen; i++) {
          const x = toX(offset + i);
          const y = toY(displayed[i]);
          if (i === 0) ctx.moveTo(x, y);
          else ctx.lineTo(x, y);
        }
        ctx.stroke();
      }

      // Border
      ctx.strokeStyle = '#ddd';
      ctx.lineWidth = 1;
      ctx.setLineDash([]);
      ctx.strokeRect(PAD_L, PAD_T, plotW, plotH);

      rafRef.current = requestAnimationFrame(draw);
    };

    rafRef.current = requestAnimationFrame(draw);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [dataRef, tOn, tOff]);

  return (
    <div className="card signal-card">
      <h3>Activation Signal</h3>
      <div ref={containerRef} style={{ width: '100%' }}>
        <canvas
          ref={canvasRef}
          style={{ display: 'block' }}
        />
      </div>
    </div>
  );
}

export default SignalChart;
